// src/components/modals/ExpenseModal.js
import React, { useState, useEffect } from "react";
import { useApp } from "../../context/AppContext";
import { expenseAPI } from "../../utils/api";
import toast from "react-hot-toast";
import KhmerDateInput from "../KhmerDateInput";

const CATEGORIES = [
  { value: "food", emoji: "🍚" },
  { value: "coffee", emoji: "☕" },
  { value: "water", emoji: "💧" },
  { value: "transport", emoji: "🚗" },
  { value: "clothing", emoji: "👕" },
  { value: "health", emoji: "💊" },
  { value: "entertainment", emoji: "🎮" },
  { value: "education", emoji: "📚" },
  { value: "utilities", emoji: "💡" },
  { value: "shopping", emoji: "🛍️" },
  { value: "other", emoji: "💸" },
];

const PAYMENT_METHODS = ["cash", "qr", "card", "transfer"];

const defaultForm = {
  itemName: "",
  category: "food",
  quantity: 1,
  date: new Date().toISOString().split("T")[0],
  amount: "",
  currency: "USD",
  exchangeRate: 4100,
  paymentMethod: "cash",
  noted: "",
  imageQr: "",
};

export default function ExpenseModal({ isOpen, onClose, editData, onSuccess }) {
  const { t, language } = useApp();

  const [form, setForm] = useState(defaultForm);
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [qrPreview, setQrPreview] = useState(null);

  useEffect(() => {
    if (editData) {
      setForm({
        itemName: editData.itemName || "",
        category: editData.category || "food",
        quantity: editData.quantity || 1,
        date: editData.date
          ? new Date(editData.date).toISOString().split("T")[0]
          : defaultForm.date,
        amount: editData.amount || "",
        currency: editData.currency || "USD",
        exchangeRate: editData.exchangeRate || 4100,
        paymentMethod: editData.paymentMethod || "cash",
        noted: editData.noted || "",
        imageQr: editData.imageQr || "",
      });
      setQrPreview(editData.imageQr || null);
    } else {
      setForm(defaultForm);
      setQrPreview(null);
      setErrors({});
    }
  }, [editData, isOpen]);

  const handleChange = (e) => {
    const { name, value } = e.target;

    setForm((prev) => ({
      ...prev,
      [name]: value,
    }));

    setErrors((prev) => ({
      ...prev,
      [name]: "",
    }));
  };

  const handleQrUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
      setForm((prev) => ({ ...prev, imageQr: reader.result }));
      setQrPreview(reader.result);
      setErrors((prev) => ({ ...prev, imageQr: "" }));
    };
    reader.readAsDataURL(file);
  };

  const validateForm = () => {
    const newErrors = {};

    if (!form.itemName.trim()) newErrors.itemName = "Item name is required";

    if (!form.date) newErrors.date = "Date is required";

    if (!form.amount || Number(form.amount) <= 0)
      newErrors.amount = "Amount must be greater than 0";

    if (!form.quantity || Number(form.quantity) <= 0)
      newErrors.quantity = "Quantity must be greater than 0";

    if (
      form.currency === "KHR" &&
      (!form.exchangeRate || Number(form.exchangeRate) <= 0)
    )
      newErrors.exchangeRate = "Exchange rate is required";

    if (form.paymentMethod === "qr" && !form.imageQr)
      newErrors.imageQr = "QR image is required";

    setErrors(newErrors);

    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async () => {
    if (!validateForm()) {
      toast.error("Please fill all required fields");
      return;
    }

    setLoading(true);

    try {
      if (editData) {
        await expenseAPI.update(editData._id, form);
        toast.success(t("updatedSuccess"));
      } else {
        await expenseAPI.create(form);
        toast.success(t("addedSuccess"));
      }

      setErrors({});
      onSuccess();
      onClose();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  const inputClass = (field) =>
    `form-input ${errors[field] ? "border-red-500 ring-red-500" : ""}`;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-box max-w-lg" onClick={(e) => e.stopPropagation()}>
        <div className="p-5 space-y-4">
          {/* Date */}
          <div>
            <label className="form-label">Date *</label>
            <KhmerDateInput
              name="date"
              value={form.date}
              onChange={handleChange}
            />
            {errors.date && (
              <p className="text-red-500 text-xs mt-1">{errors.date}</p>
            )}
          </div>

          {/* Item Name */}
          <div>
            <label className="form-label">Item Name *</label>
            <input
              type="text"
              name="itemName"
              value={form.itemName}
              onChange={handleChange}
              className={inputClass("itemName")}
            />
            {errors.itemName && (
              <p className="text-red-500 text-xs mt-1">{errors.itemName}</p>
            )}
          </div>

          {/* Amount */}
          <div>
            <label className="form-label">Amount *</label>
            <input
              type="number"
              name="amount"
              value={form.amount}
              onChange={handleChange}
              className={inputClass("amount")}
            />
            {errors.amount && (
              <p className="text-red-500 text-xs mt-1">{errors.amount}</p>
            )}
          </div>

          {/* Quantity */}
          <div>
            <label className="form-label">Quantity *</label>
            <input
              type="number"
              name="quantity"
              value={form.quantity}
              onChange={handleChange}
              className={inputClass("quantity")}
            />
            {errors.quantity && (
              <p className="text-red-500 text-xs mt-1">{errors.quantity}</p>
            )}
          </div>

          {/* Exchange Rate */}
          {form.currency === "KHR" && (
            <div>
              <label className="form-label">Exchange Rate *</label>
              <input
                type="number"
                name="exchangeRate"
                value={form.exchangeRate}
                onChange={handleChange}
                className={inputClass("exchangeRate")}
              />
              {errors.exchangeRate && (
                <p className="text-red-500 text-xs mt-1">
                  {errors.exchangeRate}
                </p>
              )}
            </div>
          )}

          {/* QR Upload */}
          {form.paymentMethod === "qr" && (
            <div>
              <label className="form-label">QR Image *</label>
              <input
                type="file"
                accept="image/*"
                onChange={handleQrUpload}
                className={inputClass("imageQr")}
              />
              {errors.imageQr && (
                <p className="text-red-500 text-xs mt-1">{errors.imageQr}</p>
              )}
            </div>
          )}

          <div className="flex gap-3 pt-4">
            <button className="btn btn-secondary flex-1" onClick={onClose}>
              Cancel
            </button>

            <button
              className="btn btn-primary flex-1"
              onClick={handleSubmit}
              disabled={loading}
            >
              {loading ? "Loading..." : "Save"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
